import React from 'react';
import { Col , Row , Card , Button , Nav } from 'react-bootstrap';
import '../styles/Projects.css';

class Project extends React.Component{

    constructor(props){
        super(props)

        this.state = {
            isFlipped: true,
            title: props.title,
            descrip: props.descrip,
            url: props.url,
            git: props.git,
            finished: props.finished
        }

        this.flip = this.flip.bind(this)
    }

    flip(){
        this.setState((prevState)=> ({isFlipped: !prevState.isFlipped}))
    }

    render(){
        const { isFlipped , title, descrip, url, git, finished } = this.state
        return(
            <div style={{width:'100%', height:'100%'}} /* onClick={this.flip} */>
                {
                    isFlipped ? (
                        <Card 
                            style={{ width: '100%', height: '100%' }}
                        >
                            <Card.Body>
                                <Card.Title>{title}</Card.Title>
                                <Card.Text>
                                    {descrip}
                                </Card.Text>
                                <div className='botones'>
                                    <Nav>
                                        <Nav.Link href={git}>
                                            <Button variant="outline-dark">Github</Button>
                                        </Nav.Link>
                                        <Nav.Link href={url}>
                                            <Button 
                                                variant="info"
                                                className={ finished ? '' : 'disabled'}    
                                            >Website</Button>
                                        </Nav.Link>
                                    </Nav>
                                </div>
                            </Card.Body>
                        </Card>
                    )
                    :
                    (
                        <div style={{width:'100%', height:'100%', padding:'30px'}}>
                            It is not flipped
                        </div>
                    )
                }
            </div>
            
        )
    }
}

const Projects = ()=>{
    return(
        <div className='projects' id='projects'>
            <h2>Projects</h2>
            <Row className='projecol'>
                <Col xs={12} lg={6}>
                    <Project 
                        title="Weather App" 
                        descrip="Simple weather app made with Express.js, using Mapbox's and Weatherstack's API."
                        git="https://github.com/queondatodotranqui/NodeWeatherApp"
                        url="https://vera-weather-app.herokuapp.com/"
                        finished={true}
                    />
                </Col>
                <Col xs={12} lg={6}>
                    <Project 
                        title="Shisou"
                        descrip="A Twitter clone made with Node.js and React.js, using MongoDB, Mongoose and Socket.io"
                        git="https://github.com/queondatodotranqui/Shisou"
                        url="#"
                        finished={false}
                    />
                </Col>
                <Col xs={12} lg={6}>
                    <Project 
                        title="Choosing App"
                        descrip="A decision-making app for choosing what to eat by inputs, made with React.js"
                        git="https://github.com/queondatodotranqui/ChoosingApp"
                        url="#"
                        finished={false}
                    />
                </Col>
                <Col xs={12} lg={6}>
                    <Project
                        title="Task App"
                        descrip="Task writing app with user system. Made with Express.js and MongoDB"
                        git="https://github.com/queondatodotranqui/TaskApp"
                        url="#"
                        finished={false}
                    />
                </Col>
            </Row>
        </div>
    )
}

export default Projects;